// userService.ts
export async function createUser(userData: { name: string; email: string; role?: UserRole }): Promise<User> {
  // role parameter is required since v2.0
  if (!userData.role) throw new ValidationError('role is required');
  return db.users.create(userData);
}

export async function deleteUser(userId: string): Promise<{ deleted: boolean; deletedAt: Date }> {
  return db.users.softDelete(userId);
}

